const minuteTicker = (() => {
  let subscribers = new Set();
  let timeoutId = null;
  let intervalId = null;
  const notify = () => {
    const now = Date.now();
    subscribers.forEach((cb) => cb(now));
  };
  const clear = () => {
    if (timeoutId) clearTimeout(timeoutId);
    if (intervalId) clearInterval(intervalId);
    timeoutId = null;
    intervalId = null;
  };
  const schedule = () => {
    clear();
    const now = Date.now();
    const delay = 60000 - (now % 60000);
    timeoutId = setTimeout(() => {
      notify();
      intervalId = setInterval(notify, 60000);
    }, delay);
  };
  return {
    subscribe(callback) {
      subscribers.add(callback);
      if (subscribers.size === 1) {
        schedule();
      }
      return () => {
        subscribers.delete(callback);
        if (!subscribers.size) {
          clear();
        }
      };
    },
  };
})();

const useMinuteTicker = (active = true) => {
  const [now, setNow] = useState(() => Date.now());
  useEffect(() => {
    if (!active) return undefined;
    setNow(Date.now());
    return minuteTicker.subscribe(setNow);
  }, [active]);
  return active ? now : null;
};

const resolveInterFontFamily = (fontWeight) => {
  if (typeof fontWeight === "string") {
    if (fontWeight.toLowerCase() === "bold") return INTER_FONTS.bold;
    if (fontWeight.toLowerCase() === "normal") return INTER_FONTS.regular;
  }
  const numericWeight = Number(fontWeight) || 0;
  if (numericWeight >= 900) return INTER_FONTS.black;
  if (numericWeight >= 800) return INTER_FONTS.extraBold;
  if (numericWeight >= 700) return INTER_FONTS.bold;
  if (numericWeight >= 600) return INTER_FONTS.semiBold;
  if (numericWeight >= 500) return INTER_FONTS.medium;
  if (numericWeight >= 300) return INTER_FONTS.light;
  return INTER_FONTS.regular;
};

const FormattingLanguageContext = React.createContext(DEFAULT_LANGUAGE);

const AppText = React.memo(
  forwardRef(function AppText({ style, ...props }, ref) {
    const formattingLanguage = useContext(FormattingLanguageContext);
    const {
      allowFontScaling = false,
      maxFontSizeMultiplier = 1,
      ...restProps
    } = props || {};
    const localizedChildren = localizeTextTreeDigits(restProps.children, formattingLanguage);
    const textProps =
      localizedChildren === restProps.children
        ? restProps
        : { ...restProps, children: localizedChildren };
    const baseStyles = Array.isArray(style) ? style.filter(Boolean) : style ? [style] : [];
    const flattened = baseStyles.length ? StyleSheet.flatten(baseStyles) || {} : {};
    const isRtlLayout = isRtlLanguage(formattingLanguage);
    const directionStyle = isRtlLayout ? { writingDirection: "rtl", textAlign: "right" } : null;
    const styleWithDirection = directionStyle ? [directionStyle, ...baseStyles] : baseStyles;
    if (flattened.fontFamily) {
      return (
        <RNText
          ref={ref}
          style={styleWithDirection.length ? styleWithDirection : style}
          allowFontScaling={allowFontScaling}
          maxFontSizeMultiplier={maxFontSizeMultiplier}
          {...textProps}
        />
      );
    }
    if (isRtlLayout) {
      return (
        <RNText
          ref={ref}
          style={styleWithDirection.length ? styleWithDirection : style}
          allowFontScaling={allowFontScaling}
          maxFontSizeMultiplier={maxFontSizeMultiplier}
          {...textProps}
        />
      );
    }
    const resolvedFontFamily = resolveInterFontFamily(flattened.fontWeight);
    const fontStyle = { fontFamily: resolvedFontFamily };
    const nextStyle = styleWithDirection.length ? [...styleWithDirection, fontStyle] : fontStyle;
    return (
      <RNText
        ref={ref}
        style={nextStyle}
        allowFontScaling={allowFontScaling}
        maxFontSizeMultiplier={maxFontSizeMultiplier}
        {...textProps}
      />
    );
  })
);

