const FREQUENCY_CRITICAL_WINDOW_MS = 2 * 60 * 60 * 1000;
const FREQUENCY_REMINDER_INTERVAL_MS = 30 * 60 * 1000;
const FREQUENCY_REMINDER_GRACE_MS = 30 * 60 * 1000;
