const buildFrequencyReminderSchedule = (nextCheckAt, now = Date.now(), options = {}) => {
  if (!Number.isFinite(nextCheckAt)) return [];
  const strictTime = options?.strictTime === true;
  if (strictTime) {
    return nextCheckAt > now ? [nextCheckAt] : [];
  }
  const windowStart = nextCheckAt - FREQUENCY_CRITICAL_WINDOW_MS;
  const windowEnd = nextCheckAt + FREQUENCY_REMINDER_GRACE_MS;
  if (!Number.isFinite(windowStart) || !Number.isFinite(windowEnd)) return [];
  if (now > windowEnd) return [];
  const triggers = [];
  for (
    let trigger = nextCheckAt - FREQUENCY_REMINDER_INTERVAL_MS;
    trigger <= windowEnd;
    trigger += FREQUENCY_REMINDER_INTERVAL_MS
  ) {
    if (trigger > now && trigger >= windowStart) {
      triggers.push(trigger);
    }
  }
  return triggers.sort((a, b) => a - b);
};

const normalizeInteractionKey = (value) => {
  if (typeof value !== "string") return null;
  const trimmed = value.trim();
  return trimmed.length ? trimmed : null;
};

const buildHistoryInteractionMap = (entries = []) => {
  if (!Array.isArray(entries) || !entries.length) return {};
  const map = {};
  entries.forEach((entry) => {
    if (!entry || (entry.kind !== "refuse_spend" && entry.kind !== "spend")) return;
    const templateId =
      normalizeInteractionKey(entry?.meta?.templateId) ||
      normalizeInteractionKey(entry?.meta?.id) ||
      normalizeInteractionKey(entry?.meta?.template);
    if (!templateId) return;
    const timestamp = Number(entry.timestamp) || 0;
    if (!timestamp) return;
    const bucket = map[templateId] || {
      saveCount: 0,
      spendCount: 0,
      timestamps: [],
    };
    bucket.timestamps.push(timestamp);
    if (entry.kind === "refuse_spend") {
      bucket.saveCount += 1;
    } else if (entry.kind === "spend") {
      bucket.spendCount += 1;
    }
    map[templateId] = bucket;
  });
  Object.values(map).forEach((bucket) => {
    bucket.timestamps.sort((a, b) => b - a);
    bucket.lastInteractionAt = bucket.timestamps[0] || null;
    bucket.previousInteractionAt = bucket.timestamps[1] || null;
    bucket.secondPreviousInteractionAt = bucket.timestamps[2] || null;
    delete bucket.timestamps;
  });
  return map;
};

const getRussianPluralWord = (count, one, few, many) => {
  const safeCount = Math.abs(Math.round(Number(count) || 0));
  const mod10 = safeCount % 10;
  const mod100 = safeCount % 100;
  if (mod10 === 1 && mod100 !== 11) return one;
  if (mod10 >= 2 && mod10 <= 4 && (mod100 < 10 || mod100 >= 20)) return few;
  return many;
};
const formatSaveCountValue = (count = 0, language = DEFAULT_LANGUAGE) => {
  const safeCount = Math.max(0, Math.floor(Number(count) || 0));
  const locale = getFormatLocale(language) || "en-US";
  return safeCount.toLocaleString(locale);
};
const formatSaveCountLabel = (count = 0, language = DEFAULT_LANGUAGE) => {
  const safeCount = Math.max(0, Math.floor(Number(count) || 0));
  const formattedCount = formatSaveCountValue(safeCount, language);
  const normalizedLanguage = normalizeLanguage(language);
  const translationLanguage = resolveTranslationLanguage(normalizedLanguage);
  if (normalizedLanguage === "ru") {
    const suffix = getRussianPluralWord(safeCount, "сохранение", "сохранения", "сохранений");
    return `${formattedCount} ${suffix}`;
  }
  if (translationLanguage === "es") {
    return `${formattedCount} ${safeCount === 1 ? "ahorro" : "ahorros"}`;
  }
  if (translationLanguage === "fr") {
    return `${formattedCount} ${safeCount === 1 ? "economie" : "economies"}`;
  }
  if (translationLanguage === "de") {
    return `${formattedCount} ${safeCount === 1 ? "Sparschritt" : "Sparschritte"}`;
  }
  if (translationLanguage === "ar") {
    return `${formattedCount} ${safeCount === 1 ? "توفير" : "عمليات توفير"}`;
  }
  if (translationLanguage === "zh") {
    return `${formattedCount} 次节省`;
  }
  return `${formattedCount} ${safeCount === 1 ? "save" : "saves"}`;
};

const shortenGoalContextTitle = (value, maxLength = 24) => {
  const normalized = String(value || "")
    .replace(/\s+/g, " ")
    .trim();
  if (!normalized) return "";
  if (normalized.length <= maxLength) return normalized;
  return `${normalized.slice(0, Math.max(1, maxLength - 3)).trim()}...`;
};

const buildGoalCompletionHeroLine = ({
  language = DEFAULT_LANGUAGE,
  title = "",
  count = 0,
  hasOther = false,
} = {}) => {
  const normalizedLanguage = normalizeLanguage(language);
  const safeCount = Math.max(0, Number(count) || 0);
  if (!safeCount) {
    const fallbackMap = {
      ru: "Цель достигнута. Отличный темп.",
      en: "Goal reached. Keep this momentum.",
      es: "Meta lograda. Mantén este ritmo.",
      fr: "Objectif atteint. Garde ce rythme.",
      de: "Ziel erreicht. Genau so weitermachen.",
      "ar-sa": "تم تحقيق الهدف. استمر بهذا الإيقاع.",
      "ar-ae": "تم تحقيق الهدف. استمر بهذا الإيقاع.",
      zh: "目标达成，继续保持这个节奏。",
    };
    return fallbackMap[normalizedLanguage] || fallbackMap.en;
  }
  const locale = getFormatLocale(normalizedLanguage) || "en-US";
  const compactTitle = shortenGoalContextTitle(stripEmojis(title || ""), 24) || title || "цели";
  const formattedCount = safeCount.toLocaleString(locale);
  if (normalizedLanguage === "ru") {
    const actionWord = getRussianPluralWord(safeCount, "отказ", "отказа", "отказов");
    const suffix = hasOther ? " и других" : "";
    return `Цель достигнута: ${formattedCount} ${actionWord} от ${compactTitle}${suffix}.`;
  }
  if (normalizedLanguage === "es") {
    const suffix = hasOther ? " y otras" : "";
    return `Meta lograda: ${formattedCount} rechazos de ${compactTitle}${suffix}.`;
  }
  if (normalizedLanguage === "fr") {
    const suffix = hasOther ? " et autres" : "";
    return `Objectif atteint : ${formattedCount} refus de ${compactTitle}${suffix}.`;
  }
  if (normalizedLanguage === "de") {
    const suffix = hasOther ? " und weitere" : "";
    return `Ziel erreicht: ${formattedCount} Ablehnungen bei ${compactTitle}${suffix}.`;
  }
  if (normalizedLanguage === "ar-sa" || normalizedLanguage === "ar-ae") {
    const suffix = hasOther ? " وغيرها" : "";
    return `تم تحقيق الهدف: ${formattedCount} رفضًا لـ ${compactTitle}${suffix}.`;
  }
  if (normalizedLanguage === "zh") {
    const suffix = hasOther ? "及其他" : "";
    return `目标达成：对 ${compactTitle} 的拒绝次数为 ${formattedCount}${suffix}。`;
  }
  const suffix = hasOther ? " and others" : "";
  return `Goal reached: ${formattedCount} skips on ${compactTitle}${suffix}.`;
};

