      const forceGroupRaw = resolveNonEmptyString(resolvedConfig.forceGroup || "").toUpperCase();
      const forceGroup = MONETIZATION_EXPERIMENT_GROUP_VALUES.has(forceGroupRaw) ? forceGroupRaw : "";

