        (entry.reminderNotificationIds || []).forEach((id) => {
          safeNotifications.cancelScheduledNotificationAsync(id);
        });
        logEvent("challenge_cancelled", { challenge_id: challengeId });
        return {
          ...prev,
          [challengeId]: createChallengeEntry(challengeId),
        };
