            setEmojiOverrides({});
            setQuickTemptations([]);
            setFreeDayStats({ ...INITIAL_FREE_DAY_STATS });
            setUsageStreak({ ...INITIAL_USAGE_STREAK });
            setUsageStreakHydrated(true);
