  ONBOARDING_CUSTOM_HABIT_COPY[resolveTranslationLanguage(normalizeLanguage(language))] ||
  ONBOARDING_CUSTOM_HABIT_COPY[getShortLanguageKey(normalizeLanguage(language))] ||
  ONBOARDING_CUSTOM_HABIT_COPY.en;

